update batch.outbox_event
set publish_status = #{status},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}

update batch.outbox_event
set publish_status = #{status},
    next_publish_at = #{nextPublishAt},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}

